// ── ROUTER ACTION TMA v2 ─────────────────────────────────────
// Reçoit le JSON de la Mini App et construit la requête SQL
const raw  = $input.first().json;
const body = raw.body || raw;

const action = body.action || '';
const chatId = String(body.chatId || '');

function esc(v) {
  if (v === null || v === undefined || String(v).trim() === '' || v === 'null') return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function escNum(v) {
  const n = parseFloat(v);
  return isNaN(n) ? 0 : n;
}

// Champs communs
const nom    = body.nom    || '';
const oldNom = body.oldNom || '';
const newNom = body.newNom || '';
const desc   = body.desc   !== undefined ? body.desc   : null;
const cat    = body.cat    || '';
const prix   = escNum(body.prix);
const taille = body.taille !== undefined ? body.taille : null;

let sql  = '';
let mode = action;
let meta = {};

switch (action) {

  case 'get_profile':
    sql = `SELECT nom_boutique, description, telephone, adresse, statut
           FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1`;
    break;

  case 'login':
    sql = `SELECT COUNT(*) AS cnt FROM vendeurs
           WHERE telegram_chat_id = ${esc(chatId)}
           AND password = ${esc(body.password || '')}`;
    break;

  case 'logout':
    sql = `INSERT INTO vendor_sessions (chat_id, step, data, authenticated)
           VALUES (${esc(chatId)}, NULL, '{}', 0)
           ON DUPLICATE KEY UPDATE step=NULL, data='{}', authenticated=0`;
    break;

  case 'register': {
    const nb  = body.nom_boutique || '';
    const pwd = body.password || '';
    sql = `INSERT IGNORE INTO vendeurs
             (telegram_chat_id, nom_boutique, description, telephone, adresse, password, statut)
           VALUES
             (${esc(chatId)}, ${esc(nb)}, ${esc(body.description)},
              ${esc(body.telephone)}, ${esc(body.adresse)}, ${esc(pwd)}, 'en_attente')`;
    meta.nom_boutique = nb;
    break;
  }

  case 'list_categories':
    sql = `SELECT c.nom FROM categories_vendeur c
           JOIN vendeurs v ON v.id = c.vendeur_id
           WHERE v.telegram_chat_id = ${esc(chatId)}
           ORDER BY c.nom`;
    break;

  case 'add_category':
    // INSERT ... SELECT avec vérification : on enregistre aussi le chatId pour debug
    sql = `INSERT INTO categories_vendeur (vendeur_id, nom)
           SELECT id, ${esc(nom)} FROM vendeurs
           WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1`;
    meta.debug = `chatId=${chatId} nom=${nom}`;
    break;

  case 'update_category':
    sql = `UPDATE categories_vendeur
           SET nom = ${esc(newNom)}
           WHERE nom = ${esc(oldNom)}
             AND vendeur_id = (SELECT id FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1)`;
    break;

  case 'delete_category':
    sql = `DELETE FROM categories_vendeur
           WHERE nom = ${esc(nom)}
             AND vendeur_id = (SELECT id FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1)`;
    break;

  case 'list_products':
    sql = `SELECT p.nom, p.prix, p.description, p.taille
           FROM produits_vendeur p
           JOIN vendeurs v ON v.id = p.vendeur_id
           WHERE v.telegram_chat_id = ${esc(chatId)}
           ORDER BY p.nom`;
    break;

  case 'add_product':
    // Deux étapes : d'abord récupérer vendeur_id + categorie_id, puis INSERT
    // On fait un INSERT ... SELECT avec sous-requêtes séparées
    sql = `INSERT INTO produits_vendeur (vendeur_id, categorie_id, nom, description, prix, taille)
           SELECT
             v.id,
             (SELECT id FROM categories_vendeur WHERE vendeur_id = v.id AND nom = ${esc(cat)} LIMIT 1),
             ${esc(nom)},
             ${esc(desc)},
             ${prix},
             ${esc(taille)}
           FROM vendeurs v
           WHERE v.telegram_chat_id = ${esc(chatId)}
           LIMIT 1`;
    meta.debug = `chatId=${chatId} cat=${cat} nom=${nom} prix=${prix}`;
    break;

  case 'update_product':
    sql = `UPDATE produits_vendeur
           SET
             nom         = ${esc(nom)},
             description = ${esc(desc)},
             prix        = ${prix},
             taille      = ${esc(taille)}
           WHERE nom = ${esc(oldNom)}
             AND vendeur_id = (SELECT id FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1)`;
    break;

  case 'delete_product':
    sql = `DELETE FROM produits_vendeur
           WHERE nom = ${esc(nom)}
             AND vendeur_id = (SELECT id FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1)`;
    break;

  default:
    return [{ json: { error: 'Action inconnue', action } }];
}

return [{ json: { action: mode, chatId, sql, meta } }];

// ── FORMATTER RÉPONSE v2 ──────────────────────────────────────
// Robuste : gère tous les formats de retour MySQL n8n (objet, tableau, vide)
const action = $('Router Action TMA').first().json.action;
const meta   = $('Router Action TMA').first().json.meta || {};
const allRows = $input.all();

// Normalisation : extraire tous les objets JSON des résultats
const rows = allRows.map(i => i.json).filter(r => r !== null && r !== undefined);
const first = rows[0] || {};

// Lecture robuste de affectedRows : n8n peut retourner
// { affectedRows: N } ou [{ affectedRows: N }] ou même { fieldCount:0, affectedRows:N }
function getAffected() {
  if (typeof first.affectedRows === 'number') return first.affectedRows;
  if (typeof first.affectedRows === 'string') return parseInt(first.affectedRows) || 0;
  // Parfois n8n wrappe dans un sous-objet
  const nested = first[0];
  if (nested && typeof nested.affectedRows === 'number') return nested.affectedRows;
  // Fallback : si rows n'est pas vide et qu'il n'y a pas de colonnes de SELECT
  // c'est probablement un résultat DML réussi
  if (rows.length > 0 && !('nom' in first) && !('cnt' in first) && !('nom_boutique' in first)) {
    // Considéré comme succès si on a au moins un objet retourné (même vide)
    return rows.length;
  }
  return 0;
}

function getInsertId() {
  if (typeof first.insertId === 'number') return first.insertId;
  if (typeof first.insertId === 'string') return parseInt(first.insertId) || 0;
  return 0;
}

switch (action) {

  case 'get_profile': {
    if (!first || !first.nom_boutique) return [{ json: { error: 'profil_not_found' } }];
    return [{ json: { ...first } }];
  }

  case 'login': {
    const cnt = parseInt(first.cnt ?? first['COUNT(*)'] ?? 0);
    if (cnt > 0) {
      const chatId = $('Router Action TMA').first().json.chatId;
      return [{ json: { success: true, _saveSession: true, chatId } }];
    }
    return [{ json: { error: 'password_incorrect' } }];
  }

  case 'logout':
    return [{ json: { success: true } }];

  case 'register': {
    const aff = getAffected();
    const iid = getInsertId();
    // INSERT IGNORE : affectedRows=1 si inséré, 0 si déjà existant
    if (aff > 0 || iid > 0) return [{ json: { success: true } }];
    return [{ json: { error: 'already_registered' } }];
  }

  case 'list_categories':
    return [{ json: rows.filter(r => r && r.nom) }];

  case 'list_products':
    return [{ json: rows.filter(r => r && r.nom) }];

  case 'add_category':
  case 'add_product':
  case 'update_category':
  case 'update_product':
  case 'delete_category':
  case 'delete_product': {
    const aff = getAffected();
    const iid = getInsertId();
    // Log debug pour diagnostiquer
    console.log(`[TMA] ${action} → affectedRows=${aff} insertId=${iid} rows=`, JSON.stringify(rows));
    // Succès si affectedRows > 0 OU insertId > 0
    if (aff > 0 || iid > 0) return [{ json: { success: true } }];
    // Dernière chance : si rows contient quelque chose sans être une erreur SQL
    // certaines configs n8n retournent {fieldCount:0,affectedRows:1,...}
    const anyAff = rows.find(r => (r.affectedRows > 0) || (r.insertId > 0));
    if (anyAff) return [{ json: { success: true } }];
    return [{ json: {
      error: 'op_failed',
      debug: { action, aff, iid, rows: rows.slice(0,2), meta }
    }}];
  }

  default:
    return [{ json: { error: 'action_not_handled', action } }];
}
